/* Suggested markup: <div class="uiwiki-index-marker-transition" tabindex="0"><span>Index Marker Transition</span></div> */
.uiwiki-index-marker-transition {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-index-marker-transition > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #c5bff0;
  animation: index_marker_transition 1.8s ease-in-out infinite alternate;
}
.uiwiki-index-marker-transition:hover,
.uiwiki-index-marker-transition:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes index_marker_transition {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-index-marker-transition, .uiwiki-index-marker-transition > span { animation: none; transition: none; }
}
